definition.script:
node {
  stage('Checkout') {
    git url: '@GIT_URL@', branch: '@GIT_BRANCH@'
  }
  stage('Setup Build Tools') {
    sh 'mvn --version'
    sh 'node --version'
    sh 'npm --version'
  }
  stage('Frontend Type Check') {
    dir('ai-igris-ui') {
      sh 'npm ci'
      sh 'npx tsc --noEmit'
    }
  }
  stage('Frontend Tests') {
    dir('ai-igris-ui') {
      sh 'npx vitest run'
    }
  }
  stage('Initialize Kafka') {
    sh '''
      docker compose up -d kafka
      KAFKA_CONTAINER=$(docker compose ps -q kafka)
      docker network connect jenkins-network $KAFKA_CONTAINER 2>/dev/null || true
      echo "Waiting for Kafka..."
      for i in $(seq 1 30); do
        if docker exec $KAFKA_CONTAINER kafka-broker-api-versions --bootstrap-server localhost:9092 > /dev/null 2>&1; then
          echo "Kafka is ready!"
          exit 0
        fi
        echo "Waiting... ($i/30)"
        sleep 2
      done
      echo "Kafka failed to start"
      docker compose logs kafka
      exit 1
    '''
  }
  stage('Build and Test') {
    sh 'mvn -B clean verify -Dspring.cloud.stream.kafka.binder.brokers=kafka:29092'
  }
  stage('Cleanup') {
    sh 'docker compose down -v || true'
  }
}
